import os
import subprocess
import sys
import tempfile
from pathlib import Path
import pytest

AC_UID = "ac8-nil-map-fallback"
AC_TYPE = "api"

_PROJECT = Path(os.environ.get("CLAUDE_PROJECT_DIR", Path(__file__).parents[3]))


def test_AC8():
    """
    GIVEN: scripts/graphify-enrich.py after PR1
    WHEN:  blast-radius-map.json does not exist (BA ran MICRO/SMALL tier)
    THEN:  graphify-enrich.py exits with status=skipped in graph-summary.json, zero error/exception, and DEV still receives a valid (empty) graph_context object
    """
    enrich_py = _PROJECT / "scripts" / "graphify-enrich.py"
    assert enrich_py.exists(), f"scripts/graphify-enrich.py not found at {enrich_py}"

    with tempfile.TemporaryDirectory() as tmpdir:
        test_task_id = "test-nil-map-ac8"
        env = {**os.environ, "CLAUDE_PROJECT_DIR": str(_PROJECT), "CLAUDE_GRAPHIFY_ENABLED": "auto"}
        result = subprocess.run(
            [sys.executable, str(enrich_py), "--task-id", test_task_id],
            capture_output=True, text=True, timeout=30, env=env,
            cwd=str(_PROJECT),
        )
        # Must exit 0 (advisory — never blocks)
        assert result.returncode == 0, (
            f"graphify-enrich.py must exit 0 even when blast-radius-map absent (AC8). "
            f"stderr: {result.stderr[:500]}"
        )
        # Check graph-summary.json status=skipped
        summary_path = _PROJECT / ".claude" / "dev-registry" / test_task_id / "graphify" / "graph-summary.json"
        if summary_path.exists():
            import json
            summary = json.loads(summary_path.read_text())
            assert summary.get("status") == "skipped", (
                f"graph-summary.json status must be 'skipped' when blast-radius-map absent (AC8); got {summary.get('status')}"
            )
        else:
            # Exit 0 is sufficient — graph-summary.json may not be written on skipped
            assert "skipped" in result.stdout.lower() or result.returncode == 0, (
                "graphify-enrich.py must indicate skipped status when blast-radius-map absent (AC8)"
            )
